function GUIIndieMain:onUsePropData(data)
    HostApi.log("!!!GUIIndieMain. onUsePropData")
    self.ivUsePropBg:SetVisible(true)
    local itemId = data:getNumberParam("propId")
    local number = data:getNumberParam("num")
    local name = ItemConfig:getItemNameById(itemId)
    if itemId == nil then
        HostApi.log("???GUIIndieMain.reward is nil")
        self.ivUsePropBg:SetVisible(false)
        return
    end
    GuiItemStack.showItemIcon(self.ivUsePropIcon, tonumber(itemId), 0, "")
    self.tvUsePropName:SetText(string.format(Lang:getString(name) .. "  x%s", tostring(number)))
end

function GUIIndieMain:initSeasonRank(data)
    local honorId = data:getNumberParam("honorId")
    local curSeason = SeasonConfig:getSeasonByHonorId(honorId)
    if not curSeason then
        return
    end
    local rank = data:getNumberParam("rank")
    self.curRank = rank
    local honor = data:getNumberParam("honor")
    self.curHonor = honor

    self.ivPlayerDan:SetImage(curSeason.danIcon)
    self.tvPlayerDanRank:SetText(string.format("No.%s", tostring(self.curRank)))
    self.tvPlayerHonor:SetText(tostring(self.curHonor))

end

function GUIIndieMain:isNeedLoad()
    return Game:isEnableIndie()
end

function GUIIndieMain:onShow()
    GUIManager:hideWindowByName("ToolBar.json")
    self:hideEngineWindow("Main-Control")
    self:hideEngineWindow("Main-PoleControl")
end

function GUIIndieMain:onTick(nTimeElapse)
    self:updateMoney()
end

function GUIIndieMain:updateMoney()
    local money = PlayerWallet.getMoneyByCoinId(MoneyType.Diamonds)
    self.tvCubeNumber:SetText(tostring(money))
end

function GUIIndieMain:onAdvertClick(type)
    GUIAd:show(type)
end

function GUIIndieMain:onSyncAdvertData(data)
    local type = data:getNumberParam("type")
    if type == Define.AdType.AD_CARD then
        self.tvAdGetJobTimes:SetText(tostring(data:getNumberParam("times")))

    elseif type == Define.AdType.AD_PROP then
        self.tvAdGetPropTimes:SetText(tostring(data:getNumberParam("times")))
    end
end

function GUIIndieMain:hideEngineWindow(name)
    local window = GUIManager:getWindowByName(name)
    if not window then
        return
    end
    self.windowPosRecord[name] = window:GetXPosition()
    window:SetXPosition({ 200, 0 })
end

return GUIIndieMain